solutions.javascript:
// GenericMathCalculator.ts
interface Calculator<T> {
  add(num1: T, num2: T): T;
  subtract(num1: T, num2: T): T;
  multiply(num1: T, num2: T): T;
  divide(num1: T, num2: T): T;
}

class CalculatorImpl<T> {
  add(num1: T, num2: T): T {
    if (typeof num1 === 'string' || typeof num2 === 'string') {
      return num1.toString() + num2.toString();
    }
    return num1 + num2;
  }

  subtract(num1: T, num2: T): T {
    if (typeof num1 === 'string' || typeof num2 === 'string') {
      return num1.toString() + num2.toString();
    }
    return num1 - num2;
  }

  multiply(num1: T, num2: T): T {
    if (typeof num1 === 'string' || typeof num2 === 'string') {
      return num1.toString() + num2.toString();
    }
    return num1 * num2;
  }

  divide(num1: T, num2: T): T {
    if (typeof num1 === 'string' || typeof num2 === 'string') {
      return num1.toString() + num2.toString();
    }
    if (num2 === 0) {
      throw new Error('Division by zero');
    }
    return num1 / num2;
  }
}

const calculate = (op: string, num1: any, num2: any) => {
  const calculator = new CalculatorImpl<any>();
  switch (op) {
    case 'add':
      return calculator.add(num1, num2);
    case 'subtract':
      return calculator.subtract(num1, num2);
    case 'multiply':
      return calculator.multiply(num1, num2);
    case 'divide':
      return calculator.divide(num1, num2);
    case 'concat':
      return num1.toString() + num2.toString();
    default:
      throw new Error('Invalid operator');
  }
};

// Example usage:
console.log(calculate('add', 5, 3)); // Output: 8
console.log(calculate('subtract', 10, 4)); // Output: 6
console.log(calculate('multiply', 7, 2)); // Output: 14
console.log(calculate('divide', 10, 2)); // Output: 5
console.log(calculate('add', 5, 'a')); // Output: '5a'
